+export class LRUCache<K, V> {
+  private map = new Map<K, V>();
+  constructor(private capacity: number) { if (capacity < 1) throw new Error('capacity must be >= 1'); }
+  has(key: K): boolean { return this.map.has(key); }
+  get(key: K): V | undefined {
+    if (!this.map.has(key)) return undefined;
+    const v = this.map.get(key)!; this.map.delete(key); this.map.set(key, v); // refresh recency
+    return v;
+  }
+  set(key: K, value: V): void {
+    if (this.map.has(key)) this.map.delete(key);
+    this.map.set(key, value);
+    if (this.map.size > this.capacity) this.map.delete(this.map.keys().next().value as K); // evict LRU
+  }
+  delete(key: K): boolean { return this.map.delete(key); }
+}
